<?php
namespace App\Domain\Combat;use App\Domain\Combat\Data\CombatCommand;use App\Domain\Combat\Data\CombatEncounterResult;use App\Domain\Combat\Data\CombatParticipantResult;use App\Domain\Combat\Data\CombatParticipantState;use App\Domain\Combat\Data\CombatResult;use App\Domain\Combat\Data\CombatRound;use App\Domain\Combat\Data\CombatState;use App\Domain\Combat\Data\CombatantStats;use InvalidArgumentException;
final class CombatSimulator {const MAX_ROUNDS=100;private $resolver;private $turnOrder;public function __construct(CombatActionResolver $resolver,CombatTurnOrder $turnOrder){$this->resolver=$resolver;$this->turnOrder=$turnOrder;}public function simulate(CombatantStats $character,CombatantStats $monster):CombatResult{$encounter=$this->simulateEncounter($character,[$monster]);$cp=$encounter->participant($character->identifier());$mp=$encounter->participant($monster->identifier());$winner=null;if($encounter->winnerSideIdentifier()===CombatSide::PLAYERS)$winner=$character->identifier();elseif($encounter->winnerSideIdentifier()===CombatSide::ENEMIES)$winner=$monster->identifier();return new CombatResult($encounter->status(),$winner,$encounter->roundsCount(),$cp->initialHealth(),$cp->finalHealth(),$mp->initialHealth(),$mp->finalHealth(),$encounter->rounds());}public function simulateEncounter(CombatantStats $player,array $enemies):CombatEncounterResult{if(count($enemies)<1||count($enemies)>CombatLimits::MAX_PARTICIPANTS_PER_SIDE)throw new InvalidArgumentException('Invalid enemy count.');$participants=[new CombatParticipantState($player,$player->currentHealth(),CombatSide::PLAYERS,1)];foreach(array_values($enemies) as $i=>$enemy){if(!$enemy instanceof CombatantStats)throw new InvalidArgumentException('Enemies must be combatants.');$participants[]=new CombatParticipantState($enemy,$enemy->currentHealth(),CombatSide::ENEMIES,$i+1);}return$this->run($participants);}private function run(array $participants){$initial=[];foreach($participants as $p)$initial[$p->identifier()]=$p->currentHealth();$players=$this->living($participants,CombatSide::PLAYERS);$enemies=$this->living($participants,CombatSide::ENEMIES);if(!$players||!$enemies){$status=!$players&&!$enemies?CombatResultStatus::DRAW:(!$enemies?CombatResultStatus::CHARACTER_VICTORY:CombatResultStatus::MONSTER_VICTORY);$state=new CombatState($participants,0,[],0,$status);return$this->encounterResult($state,[],$initial);}$order=$this->turnOrder->build($participants);$state=new CombatState($participants,1,$order,0,CombatStateStatus::IN_PROGRESS);$rounds=[];for($round=1;$round<=self::MAX_ROUNDS&&$state->status()===CombatStateStatus::IN_PROGRESS;$round++){$actions=[];while($state->status()===CombatStateStatus::IN_PROGRESS&&$state->roundNumber()===$round){$actor=$state->participant($state->nextActorIdentifier());$target=$actor->sideIdentifier()===CombatSide::PLAYERS?$this->lowestPosition($state->livingParticipantsForSide(CombatSide::ENEMIES)):$state->livingParticipantsForSide(CombatSide::PLAYERS)[0];$step=$this->resolver->resolve($state,new CombatCommand(null,$actor->identifier(),CombatActionType::BASIC_ATTACK,$target->identifier()));$actions[]=$step->resolvedAction();$state=$step->nextState();}$rounds[]=new CombatRound($round,$actions);}if($state->status()===CombatStateStatus::IN_PROGRESS)$state=new CombatState($state->participants(),$state->roundNumber(),[],0,CombatResultStatus::DRAW);return$this->encounterResult($state,$rounds,$initial);}private function lowestPosition($participants){usort($participants,function($a,$b){$p=$a->position()<=>$b->position();return$p!==0?$p:strcmp($a->identifier(),$b->identifier());});return$participants[0];}private function living($participants,$side){return array_values(array_filter($participants,function($p)use($side){return$p->sideIdentifier()===$side&&$p->alive();}));}private function encounterResult($state,$rounds,$initial){$participants=$state->participants();usort($participants,function($a,$b){$s=($a->sideIdentifier()===CombatSide::PLAYERS?0:1)<=>($b->sideIdentifier()===CombatSide::PLAYERS?0:1);if($s!==0)return$s;$p=$a->position()<=>$b->position();return$p!==0?$p:strcmp($a->identifier(),$b->identifier());});$results=array_map(function($p)use($initial){return new CombatParticipantResult($p->identifier(),$p->name(),$p->sideIdentifier(),$p->position(),$initial[$p->identifier()],$p->currentHealth());},$participants);$winner=$state->status()===CombatResultStatus::CHARACTER_VICTORY?CombatSide::PLAYERS:($state->status()===CombatResultStatus::MONSTER_VICTORY?CombatSide::ENEMIES:null);return new CombatEncounterResult($state->status(),$winner,count($rounds),$results,$rounds);}}
